import { Server } from '@modelcontextprotocol/sdk/server';
import { StdioServerTransport } from '@modelcontextprotocol/sdk/server/stdio';

const token = process.env.GITHUB_TOKEN;

const server = new Server({ name: 'file-browser-mcp', version: '1.2.0' });

server.setRequestHandler('tools/list', async () => ({
  tools: [
    { name: 'search_files', description: 'Search for files by name pattern', inputSchema: { type: 'object', properties: { pattern: { type: 'string' } } } },
    { name: 'read_file', description: 'Read the contents of a file', inputSchema: { type: 'object', properties: { path: { type: 'string' } } } }
  ]
}));

const transport = new StdioServerTransport();
await server.connect(transport);

